  'learn.gemstone.title': { en: 'Gemstone Guide', km: 'бһҳбһӮбҹ’бһӮбһ»бһ‘бҹ’бһ‘бҹҒбһҹбһҖбҹҚбһҸбҹ’бһ”бһјбһ„' },
  'learn.gemstone.subtitle': { en: 'Explore the world of colored gemstones вҖ” from ruby to sapphire, emerald to topaz. Learn about their unique properties, meanings, and how to choose the perfect stone.', km: 'бһҹбҹ’бһңбҹӮбһ„бһҷбһӣбҹӢбһ–бһёбһ–бһ·бһ—бһ–бһ“бҹғбһҸбҹ’бһ”бһјбһ„ вҖ” бһ–бһёбһҸбҹ’бһ”бһјбһ„бһ‘бһ‘бһ№бһҳ бһҸбҹ’бһ”бһјбһ„бһҖбһҺбҹ’бһҸбҹҖбһ„ бһҸбҹ’бһ”бһјбһ„бһҳбһҡбһҖбһҸ бһҡбһ бһјбһҸбһҠбһӣбҹӢбһҸбҹ’бһ”бһјбһ„бһ–бһҺбҹҢбҹ” бһҹбҹ’бһңбҹӮбһ„бһҷбһӣбҹӢбһ–бһёбһӣбһҖбҹ’бһҒбһҺбҹҲбһ–бһ·бһҹбҹҒбһҹ бһўбһҸбҹ’бһҗбһ“бҹҗбһҷ бһ“бһ·бһ„бһҡбһ”бҹҖбһ”бһҮбҹ’бһҡбһҫбһҹбһҡбһҫбһҹбһҸбҹ’бһ”бһјбһ„бһҠбҹҸбһӣбҹ’бһўбһҘбһҸбһҒбҹ’бһ…бҹ„бҹҮбҹ”' },
