  'learn.gemstone.faq': { en: 'Frequently Asked Questions', km: 'бһҹбҹҶбһҺбһҪбһҡбһҠбҹӮбһӣбһҹбһҪбһҡбһүбһ№бһҖбһүбһ¶бһ”бҹӢ' },
  'learn.gemstone.cta': { en: 'Discover the Perfect Gemstone', km: 'бһҹбҹ’бһңбҹӮбһ„бһҡбһҖбһҸбҹ’бһ”бһјбһ„бһҠбҹҸбһӣбҹ’бһўбһҘбһҸбһҒбҹ’бһ…бҹ„бҹҮ' },
  'learn.gemstone.cta_btn': { en: 'Book a Consultation to Learn More', km: 'бһҖбһҖбҹӢбһҖбһ¶бһҡбһ–бһ·бһӮбҹ’бһҡбҹ„бҹҮбһҠбһҫбһҳбҹ’бһ”бһёбһҹбҹ’бһңбҹӮбһ„бһҷбһӣбҹӢбһ”бһ“бҹ’бһҗбҹӮбһҳ' },
  'learn.gemstone.document_title': { en: 'Gemstone Guide | CT Diamond Jewelry' },
  'learn.gemstone.collection_desc': { en: 'CT Diamond curates a selection of the world\'s finest colored gemstones. Each stone is hand-selected for its color, clarity, and cut. Whether you prefer the deep red of a Burmese ruby or the royal blue of a Ceylon sapphire, we have the perfect gemstone waiting for you.' },
  'learn.gemstone.hardness_label': { en: 'Hardness' },
  'learn.gemstone.ruby_name': { en: 'Ruby' },
  'learn.gemstone.ruby_color': { en: 'Deep red' },
  'learn.gemstone.ruby_desc': { en: 'The king of gemstones, ruby symbolizes passion, protection, and prosperity. Our rubies are sourced from Myanmar and Mozambique, known for their vivid red color and exceptional clarity.' },
  'learn.gemstone.ruby_hardness': { en: '9 (Mohs)' },
  'learn.gemstone.sapphire_name': { en: 'Sapphire' },
  'learn.gemstone.sapphire_color': { en: 'Royal blue' },
  'learn.gemstone.sapphire_desc': { en: 'Celebrated for its stunning blue hues, sapphire represents wisdom, loyalty, and nobility. Our sapphires come from Sri Lanka and Madagascar, prized for their velvety blue color and brilliance.' },
  'learn.gemstone.sapphire_hardness': { en: '9 (Mohs)' },
  'learn.gemstone.emerald_name': { en: 'Emerald' },
  'learn.gemstone.emerald_color': { en: 'Vibrant green' },
  'learn.gemstone.emerald_desc': { en: 'The gemstone of rebirth and love, emerald captivates with its lush green color. Our emeralds from Colombia and Zambia are selected for their rich color and natural beauty.' },
  'learn.gemstone.emerald_hardness': { en: '7.5-8 (Mohs)' },
  'learn.gemstone.topaz_name': { en: 'Precious Topaz' },
  'learn.gemstone.topaz_color': { en: 'Golden to pink' },
  'learn.gemstone.topaz_desc': { en: 'Imperial topaz displays warm golden to pink tones that have made it a favorite among collectors. Our topaz comes from Brazil, known for producing the finest imperial topaz in the world.' },
  'learn.gemstone.topaz_hardness': { en: '8 (Mohs)' },
  'learn.gemstone.engagement_durability': { en: 'Consider Durability First' },
  'learn.gemstone.engagement_durability_desc': { en: 'For daily wear, choose a gemstone with a hardness of 7.5 or higher on the Mohs scale. Sapphire and ruby (9) are excellent choices for engagement rings. Emerald (7.5-8) requires more care but is still suitable with protective settings.' },
  'learn.gemstone.engagement_color': { en: 'Choose a Meaningful Color' },
  'learn.gemstone.engagement_color_desc': { en: 'Select a gemstone color that resonates with you or your partner. Blue sapphire represents loyalty and trust, ruby symbolizes passionate love, and emerald embodies hope and new beginnings. The color should also complement your skin tone.' },
  'learn.gemstone.engagement_quality': { en: 'Evaluate Color Quality' },
  'learn.gemstone.engagement_quality_desc': { en: 'For colored gemstones, color is the most important factor. Look for vivid, saturated colors without zoning or dark patches. A well-colored gemstone can be more valuable than clarity or size.' },
  'learn.gemstone.engagement_setting': { en: 'Consider the Setting' },
  'learn.gemstone.engagement_setting_desc': { en: 'Protective settings like bezel or halo settings help safeguard your gemstone. For softer stones like emerald, avoid prong settings that leave the stone edges exposed. A custom setting can enhance both beauty and durability.' },
  'learn.gemstone.engagement_expert': { en: 'Work with an Expert' },
  'learn.gemstone.engagement_expert_desc': { en: 'Our gemstone specialists will guide you through the selection process, from understanding quality factors to finding the perfect stone. We offer complimentary consultations at our Phnom Penh showroom.' },
  'learn.gemstone.care_know': { en: 'Know your stone' },
  'learn.gemstone.care_know_desc': { en: 'Different gemstones have different care requirements. Hard stones like sapphire and ruby can withstand ultrasonic cleaning, while softer stones like emerald and opal require gentle hand cleaning only.' },
  'learn.gemstone.care_temperature': { en: 'Avoid sudden temperature changes' },
  'learn.gemstone.care_temperature_desc': { en: 'Extreme temperature changes can cause thermal shock, leading to cracks or fractures in your gemstone. Remove jewelry before saunas, hot tubs, or extreme cold exposure.' },
  'learn.gemstone.care_cleaning': { en: 'Gentle cleaning only' },
  'learn.gemstone.care_cleaning_desc': { en: 'Clean gemstone jewelry with mild soap, warm water, and a soft brush. Avoid harsh chemicals, bleach, and abrasive cleaners. For valuable pieces, professional cleaning is recommended.' },
  'learn.gemstone.care_storage': { en: 'Store safely' },
  'learn.gemstone.care_storage_desc': { en: 'Store gemstone jewelry separately to prevent scratching. Harder stones can scratch softer ones. Keep each piece in a soft pouch or lined compartment. Avoid storing gemstones in direct sunlight.' },
  'learn.gemstone.faq_hardest': { en: 'Which gemstone is hardest wearing for daily use?' },
  'learn.gemstone.faq_hardest_desc': { en: 'Sapphire and ruby, both forms of corundum, are the hardest gemstones after diamond with a Mohs hardness of 9. They are excellent for everyday wear and are popular choices for engagement rings.' },
  'learn.gemstone.faq_expensive': { en: 'Are colored gemstones less expensive than diamonds?' },
  'learn.gemstone.faq_expensive_desc': { en: 'It depends on the gemstone. Fine quality rubies, sapphires, and emeralds can be equally or more expensive than diamonds of similar size. However, many beautiful gemstones offer excellent value compared to diamonds.' },
  'learn.gemstone.faq_lab': { en: 'Does CT Diamond offer lab-grown gemstones?' },
  'learn.gemstone.faq_lab_desc': { en: 'Yes, we offer both natural and lab-grown gemstones with full transparency. Lab-grown stones have the same chemical and physical properties as natural stones but are created in controlled laboratory conditions.' },
  'learn.gemstone.faq_engagement_ring': { en: 'Can I use a gemstone for an engagement ring?' },
  'learn.gemstone.faq_engagement_ring_desc': { en: 'Absolutely! Colored gemstone engagement rings are increasingly popular. We recommend harder stones like sapphire (9 on Mohs scale) for daily wear. Our team can help you design the perfect gemstone engagement ring.' },
  'learn.gemstone.faq_care': { en: 'How do I care for gemstone jewelry?' },
  'learn.gemstone.faq_care_desc': { en: 'Care depends on the specific gemstone. Generally, avoid harsh chemicals, remove jewelry during physical activities, clean gently with mild soap and warm water, and store separately. Bring your pieces to CT Diamond for professional cleaning and inspection.' },
  'learn.gemstone.cta_desc': { en: 'Whether you are choosing a gemstone for an engagement ring, a special gift, or adding to your personal collection, our experts are here to help you find the perfect stone.' },

